import{d as n}from"./app.c6a0e5b6.js";import{_ as s}from"./plugin-vue_export-helper.5a098b48.js";const a={},e=n(`<h1 id="multi-command-scripts" tabindex="-1"><a class="header-anchor" href="#multi-command-scripts" aria-hidden="true">#</a> Multi-command Scripts</h1><p>Devon offers the ability to run commands comprised of other CLI commands. This is incredibly useful for monorepos with a lot of services.</p><p>For example, instead of running <code>yarn app dev</code>, <code>yarn api dev</code>, <code>yarn ui dev</code>..., you can configure all 3 as a multi-command script with Devon, enabling you to just run <code>devon run frontends</code>.</p><h2 id="configuring" tabindex="-1"><a class="header-anchor" href="#configuring" aria-hidden="true">#</a> Configuring</h2><p>In your top-level definition file (<code>.devon.ts</code>), you can add a <code>scripts</code> object. This is where all of your Scripts will be registered. They key in this object is the same key used in the <code>devon run</code> command.</p><p>For example, to define a command that runs all frontend dev scripts:</p><div class="language-typescript ext-ts line-numbers-mode"><pre class="language-typescript"><code><span class="token keyword">import</span> <span class="token keyword">type</span> <span class="token punctuation">{</span> DefinitionFile <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@tnotifier/devon&#39;</span><span class="token punctuation">;</span>

<span class="token keyword">export</span> <span class="token keyword">const</span> config<span class="token operator">:</span> DefinitionFile <span class="token operator">=</span> <span class="token punctuation">{</span>
    <span class="token operator">...</span>
    scripts<span class="token operator">:</span> <span class="token punctuation">{</span>
        frontends<span class="token operator">:</span> <span class="token punctuation">{</span>
            desc<span class="token operator">:</span> <span class="token string">&#39;Run all required App Frontends&#39;</span><span class="token punctuation">,</span>
            commands<span class="token operator">:</span> <span class="token punctuation">[</span><span class="token punctuation">{</span>
                name<span class="token operator">:</span> <span class="token string">&#39;app&#39;</span><span class="token punctuation">,</span>
                command<span class="token operator">:</span> <span class="token string">&#39;yarn&#39;</span><span class="token punctuation">,</span>
                args<span class="token operator">:</span> <span class="token punctuation">[</span><span class="token string">&#39;app&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;dev&#39;</span><span class="token punctuation">]</span><span class="token punctuation">,</span>
            <span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token punctuation">{</span>
                name<span class="token operator">:</span> <span class="token string">&#39;ui&#39;</span><span class="token punctuation">,</span>
                command<span class="token operator">:</span> <span class="token string">&#39;yarn&#39;</span><span class="token punctuation">,</span>
                args<span class="token operator">:</span> <span class="token punctuation">[</span><span class="token string">&#39;ui&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;dev&#39;</span><span class="token punctuation">]</span><span class="token punctuation">,</span>
            <span class="token punctuation">}</span><span class="token punctuation">]</span><span class="token punctuation">,</span>
        <span class="token punctuation">}</span><span class="token punctuation">,</span>
    <span class="token punctuation">}</span><span class="token punctuation">,</span>
    <span class="token operator">...</span>
<span class="token punctuation">}</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br></div></div><h2 id="using" tabindex="-1"><a class="header-anchor" href="#using" aria-hidden="true">#</a> Using</h2><p>To use the defined Scripts, call the <code>devon run</code> command. You can supply any number of keys to the command and it will run all relevant commands. For example, <code>devon run api frontends</code> runs the <code>api</code> and <code>frontends</code> Devon scripts.</p>`,9);function p(o,t){return e}var i=s(a,[["render",p]]);export{i as default};
